#!/usr/bin/env python3
import base64, os, sys
if not os.path.isdir("screens"): sys.exit("Run from BatKnock root")
PAYLOAD = ""
with open("screens/CreateBatScreen.js", "wb") as f:
    f.write(base64.b64decode(PAYLOAD))
print("Done")
print()
print("Now run:")
print("  npx expo install expo-camera @react-native-ml-kit/text-recognition")
print("  npx expo start --clear --lan")
